229	ncclUniqueId get_nccl_id_via_tcp(MultiGpuConfig* result, const char* server_ip) {
230	    ncclUniqueId nccl_id;
231	
232	    int SERVER_PORT = 12345;  // hardcoded an arbitrary port number between 1024 and 49151 (registered ports)
233	    if (result->process_rank == 0) {
234	        ncclCheck(ncclGetUniqueId(&nccl_id));
235	
236	        int MAX_CLIENTS = result->num_processes - 1;
237	        int client_sockets[MAX_CLIENTS];
238	        int num_clients = 0;
239	        int server_socket, new_socket;
240	        struct sockaddr_in address;
241	        int addrlen = sizeof(address);
242	        int opt = 1;
243	
244	        // Step 1) create a server TCP socket
245	        if ((server_socket = socket(AF_INET, SOCK_STREAM, 0)) < 0) {
246	            printf("Socket failed");
247	            exit(EXIT_FAILURE);
248	        }
249	
250	        // Step 2) set socket options
251	        // SOL_SOCKET - means that option is configured at socket level
252	        // SO_REUSEADDR - allows to bind to an address which is in a TIME_WAIT state (already used by another socket) - useful when restarting the server
253	        // SO_REUSEPORT - allows to bind to the same port multiple times
254	        if (setsockopt(server_socket, SOL_SOCKET, SO_REUSEADDR | SO_REUSEPORT, &opt, sizeof(opt)) < 0) {
255	            printf("Setsockopt failed");
256	            exit(EXIT_FAILURE);
257	        }
258	
259	        // Step 3) set the server address and port
260	        address.sin_family = AF_INET;  // IPv4
261	        address.sin_addr.s_addr = inet_addr(server_ip); // alternatively use INADDR_ANY to bind to all interfaces, currently we only allow ethernet
262	        address.sin_port = htons(SERVER_PORT);
263	
264	        // Step 4) bind the socket to the address and port
265	        if (bind(server_socket, (struct sockaddr *)&address, sizeof(address)) < 0) {
266	            printf("Bind failed");
267	            exit(EXIT_FAILURE);
268	        }
269	
270	        // Step 5) MAX_CLIENTS specifies the maximum number of clients that can be queued for this server
271	        if (listen(server_socket, MAX_CLIENTS) < 0) {
272	            printf("Listen failed");
273	            exit(EXIT_FAILURE);
274	        }
275	
276	        // Step 6) accept connections from clients
277	        printf("Waiting for clients to connect...\n");
278	        while (num_clients < MAX_CLIENTS) {
279	            if ((new_socket = accept(server_socket, (struct sockaddr *)&address, (socklen_t*)&addrlen)) < 0) {
280	                printf("Accept failed");
281	                exit(EXIT_FAILURE);
282	            }
283	            client_sockets[num_clients++] = new_socket;
284	            printf("Client %d connected\n", num_clients);
285	        }
286	
287	        // Step 7) send the NCCL ID to all clients
288	        send_nccl_id_to_clients(&nccl_id, client_sockets, num_clients);
289	        printf("NCCL ID sent to all clients\n");
290	
291	        scloseCheck(server_socket);
292	    } else {
293	        int num_connection_attempts = 5;
294	        int time_to_sleep = 2;
295	        int client_socket;
296	        struct sockaddr_in serv_addr;
297	
298	        // Step 1) create a client TCP socket
299	        if ((client_socket = socket(AF_INET, SOCK_STREAM, 0)) < 0) {
300	            printf("Socket creation error");
301	            exit(EXIT_FAILURE);
302	        }
303	
304	        // Step 2) set the server address and port
305	        serv_addr.sin_family = AF_INET;
306	        serv_addr.sin_port = htons(SERVER_PORT);
307	        if (inet_pton(AF_INET, server_ip, &serv_addr.sin_addr) <= 0) {
308	            printf("Invalid address or address not supported");
309	            exit(EXIT_FAILURE);
310	        }
311	
312	        // Step 3) Try to connect to the server - retry up to `num_connection_attempts` times if the connection fails
313	        while (connect(client_socket, (struct sockaddr *)&serv_addr, sizeof(serv_addr)) < 0) {
314	            printf("%d Connection failed, retrying in %d seconds\n", result->process_rank, time_to_sleep);
315	            if (--num_connection_attempts == 0) {
316	                printf("Failed to connect to the server\n");
317	                exit(EXIT_FAILURE);
318	            }
319	            sleep(time_to_sleep);
320	        }
321	
322	        // Step 4) receive the NCCL ID from the server
323	        if (recv(client_socket, &nccl_id, sizeof(nccl_id), 0) <= 0) {
324	            printf("Failed to receive nccl_id");
325	            exit(EXIT_FAILURE);
326	        }
327	
328	        printf("Received NCCL ID\n");
329	        scloseCheck(client_socket);
330	    }
331	
332	    return nccl_id;
333	}
