469	#ifdef MULTI_GPU
470	    ncclCheck(ncclCommDestroy(config->nccl_comm));
471	    cudaCheck(cudaStreamDestroy(config->nccl_stream));
472	    cudaCheck(cudaEventDestroy(config->compute_nccl_sync));
473	    cudaCheck(cudaFree(config->unified_buffer));
