509	// Block NCCL stream until computations on compute_stream are done, then aggregate multiple pointers in an NCCL group.
510	// This can work either as an all-reduce (i.e., no ZeRo), or a reduce-scatter (ZeRO 1).
511	// The awkward `(&pointers)[N]` syntax ensures we are capturing the parameters as sized arrays, so that it becomes impossible
512	// to call this function if pointers and pointers_sizes do not match.
513	template<int N>
514	void multi_gpu_async_reduce_gradient(
515	        floatX* const (&pointers)[N], const size_t (&pointers_sizes)[N],
516	        MultiGpuConfig* config, cudaStream_t compute_stream) {
517	    if (config->num_processes == 1) {
518	        return; // no multi-GPU, just exit.
519	    }
520	
521	#ifdef MULTI_GPU
522	    NVTX_RANGE_FN();
523	    // mark an event on the compute stream, and immediately wait on this in the nccl stream
524	    // this means that the nccl stream won't start executing before all compute kernels that
525	    // have been submitted before this point have finished.
526	    // by using an event instead of cudaSyncStream, we avoid having to synchronize the host, and
527	    // can enqueue new work to the GPU right away.
528	    cudaCheck(cudaEventRecord(config->compute_nccl_sync, compute_stream));
529	    cudaCheck(cudaStreamWaitEvent(config->nccl_stream, config->compute_nccl_sync));
530	    ncclCheck(ncclGroupStart()); // NCCL group: aggregate all pointers in a single NCCL GPU kernel.
531	    for (int i = 0; i < N; ++i) {
532	        if(config->zero_stage == 0) {
533	            ncclCheck(ncclAllReduce(
534	                    pointers[i], pointers[i],
535	                    pointers_sizes[i],
536	                    ncclFloatX, ncclAvg,
537	                    config->nccl_comm, config->nccl_stream
538	            ));
539	        } else if(config->zero_stage == 1) {
540	            assert(pointers_sizes[i] % config->num_processes == 0);
541	            size_t shard_size = pointers_sizes[i] / config->num_processes;
542	            ptrdiff_t shard_offset = (ptrdiff_t)shard_size * config->process_rank;
543	            ncclCheck(ncclReduceScatter(
544	                    pointers[i], pointers[i] + shard_offset,
545	                    shard_size,
546	                    ncclFloatX, ncclAvg,
547	                    config->nccl_comm, config->nccl_stream
548	            ));
549	        }
550	    }
551	    ncclCheck(ncclGroupEnd());
552	#endif
553	}
554	
555	// convenience macro that only prints if the rank of process is zero
556	#define printf0(...) if (::multi_gpu_config.process_rank == 0) { printf(__VA_ARGS__); }
557	
558	void set_zero_configs(MultiGpuConfig* config, int zero_stage, size_t total_parameters) {
559	    config->zero_stage = 0;
560	    config->shard_num_parameters = total_parameters;
561	    // Check the Zero Stage and define sharding parameters
562	    if (zero_stage == 0) {
563	        printf0("| Zero Optimization is disabled                                              |\n");
564	    }
